import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { signupUser, clearError, clearSuccess } from 'host/authSlice';
import { useAppDispatch, useAppSelector } from 'host/hooks';

const Signup = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const { isLoading, error, success, user } = useAppSelector((state: any) => state.auth);

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
    role: 'USER',
  });

  useEffect(() => {
    return () => {
      dispatch(clearError());
      dispatch(clearSuccess());
    };
  }, [dispatch]);

  useEffect(() => {
    if (user && success) {
      // host can handle redirect if needed
    }
  }, [user, success]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));

    if (error) {
      dispatch(clearError());
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (formData.password !== formData.confirmPassword) {
      return;
    }

    dispatch(
      signupUser({
        name: formData.name,
        email: formData.email,
        password: formData.password,
        role: formData.role,
      })
    );
  };

  return (
    <div className="w-full max-w-xl rounded-[32px] bg-white/95 p-8 shadow-2xl backdrop-blur-md">
      <div className="text-center">
        <h3 className="text-5xl font-extrabold text-slate-950">
          Order<span className="text-cyan-600">Ease</span>
        </h3>
      </div>

      <div className="mt-8 grid grid-cols-2 border-b border-slate-300">
        <button
          onClick={() => navigate('/login')}
          className="pb-3 text-2xl font-semibold text-slate-800 transition hover:text-cyan-700"
        >
          Login
        </button>
        <button
          className="border-b-4 border-cyan-600 pb-3 text-2xl font-semibold text-cyan-700"
        >
          Sign Up
        </button>
      </div>

      <div className="mt-8">
        <h4 className="text-center text-4xl font-bold text-slate-950">
          Create Your Account
        </h4>

        <form onSubmit={handleSubmit} className="mt-8 space-y-5">
          {error && (
            <div className="rounded-2xl border border-red-200 bg-red-50 p-4 text-sm text-red-700">
              {error}
            </div>
          )}

          {success && (
            <div className="rounded-2xl border border-green-200 bg-green-50 p-4 text-sm text-green-700">
              {success}
            </div>
          )}

          <div>
            <label className="mb-2 block text-lg font-medium text-slate-800">
              Full Name
            </label>
            <input
              type="text"
              name="name"
              value={formData.name}
              onChange={handleChange}
              placeholder="Enter your full name"
              className="w-full rounded-2xl border border-slate-300 bg-white px-4 py-4 text-lg text-slate-900 outline-none placeholder:text-slate-400"
              disabled={isLoading}
              required
            />
          </div>

          <div>
            <label className="mb-2 block text-lg font-medium text-slate-800">
              Email Address
            </label>
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              placeholder="Enter your email"
              className="w-full rounded-2xl border border-slate-300 bg-white px-4 py-4 text-lg text-slate-900 outline-none placeholder:text-slate-400"
              disabled={isLoading}
              required
            />
          </div>

          <div>
            <label className="mb-2 block text-lg font-medium text-slate-800">
              Password
            </label>
            <input
              type="password"
              name="password"
              value={formData.password}
              onChange={handleChange}
              placeholder="Create password"
              className="w-full rounded-2xl border border-slate-300 bg-white px-4 py-4 text-lg text-slate-900 outline-none placeholder:text-slate-400"
              disabled={isLoading}
              required
            />
          </div>

          <div>
            <label className="mb-2 block text-lg font-medium text-slate-800">
              Confirm Password
            </label>
            <input
              type="password"
              name="confirmPassword"
              value={formData.confirmPassword}
              onChange={handleChange}
              placeholder="Confirm password"
              className="w-full rounded-2xl border border-slate-300 bg-white px-4 py-4 text-lg text-slate-900 outline-none placeholder:text-slate-400"
              disabled={isLoading}
              required
            />
          </div>

          <div>
            <label className="mb-2 block text-lg font-medium text-slate-800">
              Role
            </label>
            <select
              name="role"
              value={formData.role}
              onChange={handleChange}
              className="w-full rounded-2xl border border-slate-300 bg-white px-4 py-4 text-lg text-slate-900 outline-none"
              disabled={isLoading}
            >
              <option value="USER">User</option>
              <option value="ADMIN">Admin</option>
            </select>
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className="w-full rounded-2xl bg-gradient-to-r from-blue-700 to-blue-500 py-4 text-xl font-bold text-white shadow-md transition hover:opacity-95 disabled:cursor-not-allowed disabled:opacity-70"
          >
            {isLoading ? 'Creating Account...' : 'Sign Up'}
          </button>
        </form>

        <p className="mt-8 text-center text-lg text-slate-700">
          Already have an account?{' '}
          <button
            onClick={() => navigate('/login')}
            className="font-bold text-cyan-700"
          >
            Log In
          </button>
        </p>
      </div>
    </div>
  );
};

export default Signup;